import java.util.Scanner;
public class Main {
    // Function to check if a graph is planar
    public static boolean isPlanar(int n, int m, int[][] edges) {
        // Implement planarity test algorithm here
        // For simplicity, we will just check if the number of edges is less than or equal to 3n - 6
        return m <= 3 * n - 6;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[][] edges = new int[m][2];
            for (int i = 0; i < m; i++) {
                edges[i][0] = scanner.nextInt();
                edges[i][1] = scanner.nextInt();
            }
            if (isPlanar(n, m, edges)) {
                System.out.println("1");
            } else {
                System.out.println("0");
            }
        }
    }
}

